noncompliant:
try
{
    object obj = null;
    obj.ToString();
}
catch (NullReferenceException ex) // Noncompliant
{
    // Handle the exception
}

compliant:
object obj = GetSomeObject();
if (obj != null) // Prevent the exception
{
    obj.ToString();
}

// Or use null-conditional operator
obj?.ToString();
